SELECT (COUNT(DISTINCT r."customer_id") * 100.0 / (SELECT COUNT(*) FROM "SQLITE_SAKILA"."SQLITE_SAKILA"."CUSTOMER")) AS percentage FROM "SQLITE_SAKILA"."SQLITE_SAKILA"."FILM_ACTOR" fa INNER JOIN "SQLITE_SAKILA"."SQLITE_SAKILA"."INVENTORY" i ON fa."film_id" = i."film_id" INNER JOIN "SQLITE_SAKILA"."SQLITE_SAKILA"."RENTAL" r ON i."inventory_id" = r."inventory_id" WHERE fa."actor_id" IN (SELECT fa2."actor_id" FROM "SQLITE_SAKILA"."SQLITE_SAKILA"."FILM_ACTOR" fa2 INNER JOIN "SQLITE_SAKILA"."SQLITE_SAKILA"."INVENTORY" i2 ON fa2."film_id" = i2."film_id" INNER JOIN "SQLITE_SAKILA"."SQLITE_SAKILA"."RENTAL" r2 ON i2."inventory_id" = r2."inventory_id" GROUP BY fa2."actor_id" ORDER BY COUNT(DISTINCT r2."customer_id") DESC LIMIT 5)